import json
import re

file_path = 'temp_query_result.json'
with open(file_path, 'r') as f:
    data = json.load(f)

print('Total patents:', len(data))

patents = []
for record in data:
    patents_info = record.get('Patents_info', '')
    if 'DE-' in patents_info or 'from DE' in patents_info:
        grant_date = record.get('grant_date', '')
        month_match = re.search(r'(\d{1,2})\w{0,2}\s+(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec|January|February|March|April|May|June|July|August|September|October|November|December)', grant_date, re.IGNORECASE)
        if month_match:
            month_name = month_match.group(2).lower()
            month_map = {'jan': 1, 'feb': 2, 'mar': 3, 'apr': 4, 'may': 5, 'jun': 6, 'jul': 7, 'aug': 8, 'sep': 9, 'oct': 10, 'nov': 11, 'dec': 12, 'january': 1, 'february': 2, 'march': 3, 'april': 4, 'may': 5, 'june': 6, 'july': 7, 'august': 8, 'september': 9, 'october': 10, 'november': 11, 'december': 12}
            month = month_map.get(month_name, 0)
            if 7 <= month <= 12:
                cpc_field = record.get('cpc', '[]')
                try:
                    cpc_codes = json.loads(cpc_field.replace('\\n', '\n'))
                    for cpc in cpc_codes:
                        code = cpc.get('code', '')
                        if code and len(code) >= 6 and '/' in code:
                            level4_code = code[:6]
                            patents.append({'cpc_code': level4_code, 'full_code': code, 'month': month})
                except:
                    continue

print('Filtered patents (DE, second half 2019):', len(patents))

# Count patents per CPC code per month
cpc_month_counts = {}
for p in patents:
    code = p['cpc_code']
    month = p['month']
    if code not in cpc_month_counts:
        cpc_month_counts[code] = {}
    cpc_month_counts[code][month] = cpc_month_counts[code].get(month, 0) + 1

# Calculate EMA for each CPC code
alpha = 0.1
results = []

for code, month_counts in cpc_month_counts.items():
    # Sort months
    months = sorted(month_counts.keys())
    if len(months) < 2:
        continue

    # Calculate EMA
    ema = None
    best_month = None
    best_ema = 0

    for month in months:
        count = month_counts[month]
        if ema is None:
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_month = month

    results.append({
        'cpc_code': code,
        'best_month': best_month,
        'best_ema': best_ema,
        'total_patents': sum(month_counts.values())
    })

# Sort by best EMA
results.sort(key=lambda x: x['best_ema'], reverse=True)

top_results = results[:10]
print('Top CPC codes by EMA:')
for r in top_results:
    print(f"{r['cpc_code']}: EMA={r['best_ema']:.2f}, Best Month={r['best_month']}, Total={r['total_patents']}")

