import json, re
from collections import defaultdict

# Get the data from the storage key
data = locals()['var_functions.query_db:22']
print('Total records:', len(data))

# Group CPC level 4 codes by month
cpc_monthly = defaultdict(lambda: defaultdict(int))

for rec in data:
    cpc_str = rec.get('cpc', '')
    if not cpc_str:
        continue

    try:
        cpc_codes = json.loads(cpc_str)
        date_str = rec.get('grant_date', '').lower()

        # Determine month
        month = 0
        if 'jul' in date_str:
            month = 7
        elif 'aug' in date_str:
            month = 8
        elif 'sep' in date_str:
            month = 9
        elif 'oct' in date_str:
            month = 10
        elif 'nov' in date_str:
            month = 11
        elif 'dec' in date_str:
            month = 12

        if 7 <= month <= 12:
            for cpc in cpc_codes:
                code = cpc.get('code', '')
                if code and len(code) >= 6:
                    level4 = code[:6]
                    cpc_monthly[level4][month] += 1
    except:
        continue

# Calculate EMA (alpha=0.1)
alpha = 0.1
results = []

for cpc_code, months in cpc_monthly.items():
    ema = None
    best_month = None
    best_ema = 0

    # Process months 7-12
    for m in range(7, 13):
        count = months.get(m, 0)
        if ema is None:
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_month = m

    results.append({
        'cpc_code': cpc_code,
        'best_month': best_month,
        'ema_score': best_ema,
        'total_patents': sum(months.values())
    })

# Sort by EMA score
results.sort(key=lambda x: x['ema_score'], reverse=True)

print('Top 5 CPC codes by EMA:')
for r in results[:5]:
    print('%s: EMA=%.2f, Best Month=%d, Total=%d' % (
        r['cpc_code'], r['ema_score'], r['best_month'], r['total_patents']
    ))

# Prepare output
output_data = results[:20]
print('Prepared %d results for detailed lookup' % len(output_data))

