import json
from collections import defaultdict

# The query result is stored as a file path
file_path = var_functions.query_db:22
print('File path:', file_path)

with open(file_path, 'r') as f:
    data = json.load(f)

print('Total records:', len(data))
print('Sample record:', data[0])

# Group CPC level 4 codes by month
cpc_monthly = defaultdict(lambda: defaultdict(int))

def extract_month(date_str):
    d = date_str.lower()
    if 'jul' in d:
        return 7
    if 'aug' in d:
        return 8
    if 'sep' in d:
        return 9
    if 'oct' in d:
        return 10
    if 'nov' in d:
        return 11
    if 'dec' in d:
        return 12
    return 0

for rec in data:
    cpc_str = rec.get('cpc', '')
    if not cpc_str:
        continue

    try:
        cpc_codes = json.loads(cpc_str.replace('\n', '\n'))
        month = extract_month(rec.get('grant_date', ''))

        if 7 <= month <= 12:
            for cpc in cpc_codes:
                code = cpc.get('code', '')
                if code and len(code) >= 6:
                    level4 = code[:6]
                    cpc_monthly[level4][month] += 1
    except:
        continue

# Calculate EMA
alpha = 0.1
results = []

for cpc_code, months in cpc_monthly.items():
    ema = None
    best_month = None
    best_ema = 0

    for m in range(7, 13):
        count = months.get(m, 0)
        if ema is None:
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_month = m

    results.append({
        'cpc_code': cpc_code,
        'best_month': best_month,
        'ema_score': best_ema,
        'total_patents': sum(months.values())
    })

# Sort by EMA score
results.sort(key=lambda x: x['ema_score'], reverse=True)

top_results = results[:15]
print('Top 15 CPC codes by EMA score:')
for i, r in enumerate(top_results):
    print('%d. %s: EMA=%.2f, Best Month=%d, Total=%d' % (
        i+1, r['cpc_code'], r['ema_score'], r['best_month'], r['total_patents']
    ))

# Prepare for CPC definition lookup
cpc_codes = [r['cpc_code'] for r in top_results]
print('CPC codes to lookup:', cpc_codes[:5])

