import json
from collections import defaultdict

file_path = var_functions.query_db:22
with open(file_path, 'r') as f:
    data = json.load(f)

print('Total records:', len(data))

# Process patents
cpc_monthly = defaultdict(lambda: defaultdict(int))

for rec in data:
    cpc_str = rec.get('cpc', '')
    if not cpc_str:
        continue

    try:
        # Parse CPC codes
        cpc_str_clean = cpc_str.replace('\n', '
')
        cpc_codes = json.loads(cpc_str_clean)

        # Extract month from grant date
        grant_date = rec.get('grant_date', '').lower()
        month = 0

        if 'jul' in grant_date:
            month = 7
        elif 'aug' in grant_date:
            month = 8
        elif 'sep' in grant_date:
            month = 9
        elif 'oct' in grant_date:
            month = 10
        elif 'nov' in grant_date:
            month = 11
        elif 'dec' in grant_date:
            month = 12

        if 7 <= month <= 12:
            for cpc in cpc_codes:
                code = cpc.get('code', '')
                if code and len(code) >= 6:
                    level4 = code[:6]
                    cpc_monthly[level4][month] += 1
    except:
        continue

# Calculate EMA (alpha = 0.1)
alpha = 0.1
results = []

for cpc_code, months in cpc_monthly.items():
    ema = None
    best_month = None
    best_ema = 0

    for m in range(7, 13):
        count = months.get(m, 0)
        if ema is None:
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_month = m

    results.append({
        'cpc_code': cpc_code,
        'best_month': best_month,
        'ema_score': best_ema,
        'total_patents': sum(months.values())
    })

# Sort by EMA score descending
results.sort(key=lambda x: x['ema_score'], reverse=True)

print('Top 10 CPC codes by EMA score:')
for i, r in enumerate(results[:10]):
    print('%d. %s: EMA=%.2f, Best Month=%d, Total Patents=%d' % (
        i+1, r['cpc_code'], r['ema_score'], r['best_month'], r['total_patents']
    ))

# Store top results for CPC definition lookup
top_results = results[:20]
cpc_codes = [r['cpc_code'] for r in top_results]
print('\nCPC codes to get titles for:', cpc_codes)

