import json
from collections import defaultdict

# Get the file path
file_path = locals()['var_functions.query_db:46']

# Read data
with open(file_path, 'r') as f:
    data = json.load(f)

# Process patents
cpc_monthly = defaultdict(lambda: defaultdict(int))
second_half_patents = 0

def get_month_from_date(date_str):
    d = date_str.lower()
    if 'jul' in d:
        return 7
    if 'aug' in d:
        return 8
    if 'sep' in d:
        return 9
    if 'oct' in d:
        return 10
    if 'nov' in d:
        return 11
    if 'dec' in d:
        return 12
    return 0

for rec in data:
    grant_date = rec.get('grant_date', '')
    if not grant_date:
        continue

    month = get_month_from_date(grant_date)
    if 7 <= month <= 12:
        cpc_str = rec.get('cpc', '')
        if cpc_str:
            try:
                cpc_codes = json.loads(cpc_str)
                for cpc in cpc_codes:
                    code = cpc.get('code', '')
                    if code and len(code) >= 6 and '/' in code:
                        level4_code = code[:6]
                        cpc_monthly[level4_code][month] += 1
                        second_half_patents += 1
            except:
                continue

# Calculate EMA (alpha=0.1)
alpha = 0.1
results = []

for cpc_code, monthly in cpc_monthly.items():
    ema = None
    best_month = None
    best_ema = 0

    for m in range(7, 13):
        count = monthly.get(m, 0)
        if ema is None:
            ema = count
        else:
            ema = alpha * count + (1 - alpha) * ema

        if ema > best_ema:
            best_ema = ema
            best_month = m

    results.append({
        'cpc_code': cpc_code,
        'best_month': best_month,
        'ema_score': best_ema,
        'total_patents': sum(monthly.values())
    })

results.sort(key=lambda x: x['ema_score'], reverse=True)
top_results = results[:15]

# Output in required format
print('__RESULT__:')
print(json.dumps(top_results))

